def token_case(s):
    exceptions = {'URL', 'ID'}
    tokens = s.split('_')
    camel_case = []
    for token in tokens:
        if token not in exceptions:
            if token:  # handle edge case of an empty token (e.g., from a string trimming operation)
                if camel_case:
                    camel_case.append(token[0].upper())
                else:
                    camel_case.append(token.lower())
        else:
            camel_case.append(token)
    return ''.join(camel_case)
